str.UnknownError = localize({de: "Es gab einen unerwarteten Fehler\nBitte er\xf6ffne hier ein Support-Ticket:\n" + supportEmail + "\n\nund f\xfcge einen Screenshot der Fehlermeldung bei\n\n", en: "There was an unexpected error\nPlease please open a support ticket here:\n" + supportEmail + "\n\nand submit screenshot of this error message\n\n", es: "Se ha producido un error desconocido\nPor favor habra un ticket de soporte aqui:\n" + supportEmail + "\n\ny presente una captura de pantalla con este mensaje de error\n\n", fr: "Une erreur vient de se produire \nVeuillez ouvrir un ticket de service \xe0 cette adresse:\n" + supportEmail + "\n\net n\'oubliez pas d\'y joindre une capture d\'\xe9cran de ce message\n\n", it: "Si sono riscontrati errori inaspettati\nSi prega di aprire un ticket di supporto qui:\n" + supportEmail + "\n\ne inserire uno screenshot di questo messaggio di errore\n\n", ja: "\u4e88\u671f\u3057\u306a\u3044\u30a8\u30e9\u30fc\u304c\u8d77\u3053\u308a\u307e\u3057\u305f.\n\u3053\u3061\u3089\u304b\u3089\u30b5\u30dd\u30fc\u30c8\u30c1\u30b1\u30c3\u30c8\u3092\u958b\u3044\u3066\u304f\u3060\u3055\u3044:\n" + supportEmail + "\n\n\u30a8\u30e9\u30fc\u30e1\u30c3\u30bb\u30fc\u30b8\u306e\u30b9\u30af\u30ea\u30fc\u30f3\u30b7\u30e7\u30c3\u30c8\u3092\u63d0\u793a\u3057\u3066\u304f\u3060\u3055\u3044.\n\n", kr: "\uc608\uae30\uce58 \uc54a\uc740 \uc5d0\ub7ec\uc785\ub2c8\ub2e4. \n\uc11c\ud3ec\ud2b8 \ud2f0\ucf13\uc744 \uc5ec\uc2ed\uc2dc\uc624.:\n" + supportEmail + "\n\n\uc5d0\ub7ec \uba54\uc138\uc9c0\ub97c \uc81c\ucd9c \ud558\uc138\uc694.\n\n", pt: "Ocorreu um erro inesperado.\nPor favor abra um ticket de atendimento aqui:\n" + supportEmail + "\n\ne envie uma imagem da mensagem de erro\n\n", zh_CN: "\u53d1\u751f\u4e86\u4e00\u4e2a\u610f\u5916\u9519\u8bef\n\u8bf7\u5728\u8fd9\u91cc\u6253\u5f00\u4e00\u4e2a\u652f\u6301\u5de5\u5355:\n" + supportEmail + "\n\n\u5e76\u5c06\u8fd9\u4e2a\u9519\u8bef\u6d88\u606f\u7684\u622a\u56fe\u53d1\u9001\u7ed9\u6211\u4eec\n\n"});
